#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <unordered_map>

using namespace std;

bool isPalindrome(string num) {
    string s = num;
    int left = 0, right = s.length() - 1;
    while (left < right) {
        if (s[left] != s[right]) return false;
        left++;
        right--;
    }
    return true;
}

bool isValidNumber(string num) {
    unordered_map<char, int> count;
    for (char c : num) {
        count[c]++;
    }
    for (auto& pair : count) {
        if (pair.second != (pair.first - '0')) {
            return false;
        }
    }
    return true;
}

long long solve(long long n) {
    long long result = 0;
    for (long long i = n + 1; ; i++) {
        string s = to_string(i);
        if (isPalindrome(s) && isValidNumber(s)) {
            result = i;
            break;
        }
    }
    return result;
}
